class ListNode:
    def __init__(self, x):
        self.val = x
        self.next = None

class Solution:
    def detectCycle(self, head: ListNode) -> ListNode:
        if not head or not head.next:
            return None

        slow = head
        fast = head

        # Phase 1: Detect if a cycle exists and find the meeting point
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
            if slow == fast:
                break
        else:
            # If the loop finished without breaking, it means fast reached the end, so no cycle
            return None

        # Phase 2: If a cycle exists, find the start of the cycle
        # Reset slow pointer to the head of the list
        # Move both slow and fast one step at a time
        # The point where they meet again is the start of the cycle
        slow = head
        while slow != fast:
            slow = slow.next
            fast = fast.next

        return slow
